<template>
    <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full  d-flex">
                        <h4 class="modal-title">{{ $t('MakeProjectDefault') }}</h4>
                        <button type="button" class="close" v-on:click="CloseMakeDefault">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>
                    </div>
                    <div class="modal-body">
                        <label>
                            <b>" {{ ProjectName }}</b> " {{ $t('project is default for:') }}
                        </label>

                        <dynamic-form lang="en" :buttons="buttons" :schema="FormSchema" ref="AssignTagForm"
                            v-on:OnSubmit="onSubmit"></dynamic-form>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>

<script>
import DataService from '../../services/DataService'
export default {
    props: {
        ProjectId: {
            type: String,
            required: true,
        },
        ProjectName: {
            type: String,
            required: true
        }
    },
    data() {
        return {
            isLoading: false,
            AssignTagList: [],
            userId: null,
            companyId: null,
            UserType: null,
            FormSchema: [
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "CustomSelectField",
                            mode: "tag",
                            label: '',
                            name: "Tag",
                            value: "",
                            config: {
                                options: [],
                                //onChange: this.ChangeStatus
                            },
                            placeholder: this.$t('Select User'),
                            validationRules: { "required": false, max: 100 },
                        }
                    ]
                }
            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Save",
                    isVisible: true,
                    onClick: this.OnSubmit
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.CloseMakeDefault,
                },
            ],
        }
    },
    created: function () {
        var vm = this;
        vm.userId = vm.GetUserInfo.ID;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.UserType = vm.GetUserInfo.UserType;
        vm.companyId = vm.GetUserInfo.CompanyId;
        vm.FetchTeamListing();
    },
    methods: {
        FetchTeamListing: function () {

            var ths = this;
            var url = `projectId=${ths.ProjectId}&userName=&projectName=&designationId=&sortBy=&sortExp=&pageSize=10&pageNum=1`;
            DataService.GetTeamListing(url).then((response) => {
                if (response.data.result.data.length > 0) {
                    response.data.result.data.forEach((item) => {
                        let obj = {
                            name: item.USER_NAME,
                            value: item.USER_ID
                        }
                        ths.FormSchema[0].Data[0].config.options.push(obj);
                    })
                    ths.$refs.AssignTagForm.UpdateKeyValue();
                }
            })
        },
        CloseMakeDefault: function () {
            this.$parent.IsMakeProjectDefault = false;
        },
        OnSubmit: function () {

            var vm = this;            
            vm.confirmR(vm.$t("ConfirmMsgForProjectDefault"), true, (vm.$t("Project")), function () {
                vm.isLoading = true;
                if (vm.ProjectId != '') {

                    const valuesArray = vm.FormSchema[0].Data[0].value;
                    const resultString = valuesArray.map(item => item.value).join(',');
                    var VarObject = {
                        projectId: vm.ProjectId,
                        users: resultString
                    }
                    var objectPostString = JSON.stringify(VarObject);
                    DataService.SaveDefault(objectPostString).then(function (response) {
                        if (response.data.result == 1) {
                            vm.isLoading = false;
                            vm.ShowAlert(vm.$t('RecordUpdatedSuccessfully'), "success", true, vm.$t("Alert"));
                            vm.CloseMakeDefault();
                            vm.$parent.FetchData();
                        }
                        else {
                            vm.isLoading = false;
                            vm.ShowAlert(vm.$t('UnknownErrorOccur'), "failure", true, vm.$t("Alert"));
                        }
                    });
                }
            });
        }
    }
}
</script>