async function bindleftCommonSearchdropdown(instance, moduleName, filtername) {
    var vm = instance;
    if(filtername=='CHANNEL'){
        var url = `id=&&moduleName=${moduleName}&type=${filtername}&search=&refId=`;
        await DataService.GetDDLData(url).then((response)=>{            
            if (response.data && response.data.DATA) {
                const targetField = vm.leftSearchFields.find(field => field.fieldName === 'Channel');
                if (targetField) {
                    targetField.listOptions = response.data.DATA.map(element => ({ name: element.name, value: element.value }));
                }
            }
        })
    }
    else if(filtername=='Status'){
        var params = `statusType=${moduleName}&&hasglobal=${false}`;
        await DataService.GetStatusList(params).then(async (response) => {
            if (response.data.length > 0) { 
                const targetField = vm.leftSearchFields.find(field => field.fieldName === 'Status');
                if (targetField) {
                    targetField.listOptions = response.data.map(element => ({ name: element.STATUS, value: element.STATUS_ID }));
                }              
            }
        });
    }
};

